import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Intrinsics and Low-Level Operations","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/intrinsics.md","filePath":"archive/reference/intrinsics.md"}'),o={name:"archive/reference/intrinsics.md"};function i(r,e,l,c,p,d){return s(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="intrinsics-and-low-level-operations" tabindex="-1">Intrinsics and Low-Level Operations <a class="header-anchor" href="#intrinsics-and-low-level-operations" aria-label="Permalink to &quot;Intrinsics and Low-Level Operations&quot;">​</a></h1><p><strong>Version:</strong> 0.2.0 <strong>Last Updated:</strong> November 9, 2025</p><p>This document describes Vex&#39;s support for low-level operations, compiler intrinsics, and platform-specific features.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#bit-manipulation-intrinsics">Bit Manipulation Intrinsics</a></li><li><a href="#cpu-feature-detection">CPU Feature Detection</a></li><li><a href="#memory-intrinsics">Memory Intrinsics</a></li><li><a href="#simd-intrinsics">SIMD Intrinsics</a></li><li><a href="#platform-specific-features">Platform-Specific Features</a></li></ol><hr><h2 id="bit-manipulation-intrinsics" tabindex="-1">Bit Manipulation Intrinsics <a class="header-anchor" href="#bit-manipulation-intrinsics" aria-label="Permalink to &quot;Bit Manipulation Intrinsics&quot;">​</a></h2><p>Vex provides LLVM bit manipulation intrinsics for high-performance low-level operations.</p><h3 id="available-intrinsics" tabindex="-1">Available Intrinsics <a class="header-anchor" href="#available-intrinsics" aria-label="Permalink to &quot;Available Intrinsics&quot;">​</a></h3><h4 id="count-leading-zeros-ctlz-x" tabindex="-1">Count Leading Zeros: <code>ctlz(x)</code> <a class="header-anchor" href="#count-leading-zeros-ctlz-x" aria-label="Permalink to &quot;Count Leading Zeros: `ctlz(x)`&quot;">​</a></h4><p>Counts the number of leading zero bits in an integer.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u32 = 0b00001111_00000000_00000000_00000000; // 0x0F000000</span></span>\n<span class="line"><span>let zeros = ctlz(x); // Returns 4 (leading zeros before first 1)</span></span></code></pre></div><p><strong>Supported Types</strong>: <code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>u128</code></p><h4 id="count-trailing-zeros-cttz-x" tabindex="-1">Count Trailing Zeros: <code>cttz(x)</code> <a class="header-anchor" href="#count-trailing-zeros-cttz-x" aria-label="Permalink to &quot;Count Trailing Zeros: `cttz(x)`&quot;">​</a></h4><p>Counts the number of trailing zero bits in an integer.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u32 = 0b11110000_00000000_00000000_00000000; // 0xF0000000</span></span>\n<span class="line"><span>let zeros = cttz(x); // Returns 24 (trailing zeros)</span></span></code></pre></div><p><strong>Supported Types</strong>: <code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>u128</code></p><h4 id="population-count-popcnt-x" tabindex="-1">Population Count: <code>popcnt(x)</code> <a class="header-anchor" href="#population-count-popcnt-x" aria-label="Permalink to &quot;Population Count: `popcnt(x)`&quot;">​</a></h4><p>Counts the number of set bits (1s) in an integer.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u32 = 0b10110100_11100011_00001111_00000000; // 0xB4E30F00</span></span>\n<span class="line"><span>let count = popcnt(x); // Returns 12 (number of 1 bits)</span></span></code></pre></div><p><strong>Supported Types</strong>: <code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>u128</code></p><h4 id="bit-reverse-bitreverse-x" tabindex="-1">Bit Reverse: <code>bitreverse(x)</code> <a class="header-anchor" href="#bit-reverse-bitreverse-x" aria-label="Permalink to &quot;Bit Reverse: `bitreverse(x)`&quot;">​</a></h4><p>Reverses the bits in an integer.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u8 = 0b11010011; // 0xD3</span></span>\n<span class="line"><span>let reversed = bitreverse(x); // Returns 0b11001011 (0xCB)</span></span></code></pre></div><p><strong>Supported Types</strong>: <code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>u128</code></p><h4 id="bit-swap-bswap-x" tabindex="-1">Bit Swap: <code>bswap(x)</code> <a class="header-anchor" href="#bit-swap-bswap-x" aria-label="Permalink to &quot;Bit Swap: `bswap(x)`&quot;">​</a></h4><p>Swaps the bytes in an integer (endianness conversion).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u32 = 0x12345678;</span></span>\n<span class="line"><span>let swapped = bswap(x); // Returns 0x78563412</span></span></code></pre></div><p><strong>Supported Types</strong>: <code>u16</code>, <code>u32</code>, <code>u64</code>, <code>u128</code></p><h4 id="overflow-checks" tabindex="-1">Overflow Checks <a class="header-anchor" href="#overflow-checks" aria-label="Permalink to &quot;Overflow Checks&quot;">​</a></h4><p><strong>Signed Addition Overflow</strong>: <code>sadd_overflow(a, b)</code> → <code>(result, overflow)</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let (result, overflow) = sadd_overflow(i32::MAX, 1);</span></span>\n<span class="line"><span>if overflow {</span></span>\n<span class="line"><span>    // Handle overflow</span></span>\n<span class="line"><span>}</span></span></code></pre></div><p><strong>Signed Subtraction Overflow</strong>: <code>ssub_overflow(a, b)</code> → <code>(result, overflow)</code></p><p><strong>Signed Multiplication Overflow</strong>: <code>smul_overflow(a, b)</code> → <code>(result, overflow)</code></p><p><strong>Supported Types</strong>: <code>i8</code>, <code>i16</code>, <code>i32</code>, <code>i64</code>, <code>i128</code></p><h3 id="memory-operations" tabindex="-1">Memory Operations <a class="header-anchor" href="#memory-operations" aria-label="Permalink to &quot;Memory Operations&quot;">​</a></h3><h4 id="memory-allocation-alloc-size-→-u8" tabindex="-1">Memory Allocation: <code>alloc(size)</code> → <code>*u8</code> <a class="header-anchor" href="#memory-allocation-alloc-size-→-u8" aria-label="Permalink to &quot;Memory Allocation: `alloc(size)` → `*u8`&quot;">​</a></h4><p>Allocates <code>size</code> bytes of memory.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>unsafe {</span></span>\n<span class="line"><span>    let ptr: *u8 = alloc(1024); // Allocate 1KB</span></span>\n<span class="line"><span>    // Use ptr...</span></span>\n<span class="line"><span>    free(ptr);</span></span>\n<span class="line"><span>}</span></span></code></pre></div><h4 id="memory-free-free-ptr" tabindex="-1">Memory Free: <code>free(ptr)</code> <a class="header-anchor" href="#memory-free-free-ptr" aria-label="Permalink to &quot;Memory Free: `free(ptr)`&quot;">​</a></h4><p>Frees previously allocated memory.</p><h4 id="memory-realloc-realloc-ptr-new-size-→-u8" tabindex="-1">Memory Realloc: <code>realloc(ptr, new_size)</code> → <code>*u8</code> <a class="header-anchor" href="#memory-realloc-realloc-ptr-new-size-→-u8" aria-label="Permalink to &quot;Memory Realloc: `realloc(ptr, new_size)` → `*u8`&quot;">​</a></h4><p>Resizes allocated memory block.</p><h4 id="memory-move-memmove-dst-src-count" tabindex="-1">Memory Move: <code>memmove(dst, src, count)</code> <a class="header-anchor" href="#memory-move-memmove-dst-src-count" aria-label="Permalink to &quot;Memory Move: `memmove(dst, src, count)`&quot;">​</a></h4><p>Copies <code>count</code> bytes from <code>src</code> to <code>dst</code>, handling overlapping regions.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>unsafe {</span></span>\n<span class="line"><span>    let buffer: *u8 = alloc(1024);</span></span>\n<span class="line"><span>    // Move overlapping regions</span></span>\n<span class="line"><span>    memmove(buffer.add(10), buffer, 100);</span></span>\n<span class="line"><span>}</span></span></code></pre></div><h3 id="type-information" tabindex="-1">Type Information <a class="header-anchor" href="#type-information" aria-label="Permalink to &quot;Type Information&quot;">​</a></h3><h4 id="size-of-t-→-usize" tabindex="-1">Size Of: <code>&lt;T&gt;()</code> → <code>usize</code> <a class="header-anchor" href="#size-of-t-→-usize" aria-label="Permalink to &quot;Size Of: `&lt;T&gt;()` → `usize`&quot;">​</a></h4><p>Returns the size in bytes of type <code>T</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let size = &lt;i32&gt;();     // Returns 4</span></span>\n<span class="line"><span>let arr_size = &lt;[i32; 10]&gt;(); // Returns 40</span></span></code></pre></div><h4 id="align-of-alignof-t-→-usize" tabindex="-1">Align Of: <code>alignof&lt;T&gt;()</code> → <code>usize</code> <a class="header-anchor" href="#align-of-alignof-t-→-usize" aria-label="Permalink to &quot;Align Of: `alignof&lt;T&gt;()` → `usize`&quot;">​</a></h4><p>Returns the alignment in bytes of type <code>T</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let align = alignof&lt;i64&gt;();   // Returns 8</span></span></code></pre></div><h3 id="crypto-intrinsics" tabindex="-1">Crypto Intrinsics <a class="header-anchor" href="#crypto-intrinsics" aria-label="Permalink to &quot;Crypto Intrinsics&quot;">​</a></h3><h4 id="carry-less-multiplication-clmul-a-b" tabindex="-1">Carry-Less Multiplication: <code>clmul(a, b)</code> <a class="header-anchor" href="#carry-less-multiplication-clmul-a-b" aria-label="Permalink to &quot;Carry-Less Multiplication: `clmul(a, b)`&quot;">​</a></h4><p>Performs carry-less multiplication (XOR instead of ADD during shift-add steps). Used for CRC, GCM, and other cryptographic algorithms.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let a: u64 = 5;</span></span>\n<span class="line"><span>let b: u64 = 7;</span></span>\n<span class="line"><span>let res = clmul(a, b);</span></span></code></pre></div><p><strong>Implementation:</strong></p><ul><li><strong>x86_64:</strong> <code>PCLMULQDQ</code> instruction.</li><li><strong>ARM64:</strong> <code>PMULL</code> instruction.</li><li><strong>Software:</strong> Shift-XOR loop fallback.</li></ul><p><strong>Supported Types:</strong> <code>u64</code>, <code>i64</code></p><h3 id="array-operations" tabindex="-1">Array Operations <a class="header-anchor" href="#array-operations" aria-label="Permalink to &quot;Array Operations&quot;">​</a></h3><h4 id="array-length-array-len-arr-→-usize" tabindex="-1">Array Length: <code>array_len(arr)</code> → <code>usize</code> <a class="header-anchor" href="#array-length-array-len-arr-→-usize" aria-label="Permalink to &quot;Array Length: `array_len(arr)` → `usize`&quot;">​</a></h4><p>Returns the length of an array.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let arr: [i32; 5] = [1, 2, 3, 4, 5];</span></span>\n<span class="line"><span>let len = array_len(arr); // Returns 5</span></span></code></pre></div><h3 id="utf-8-operations" tabindex="-1">UTF-8 Operations <a class="header-anchor" href="#utf-8-operations" aria-label="Permalink to &quot;UTF-8 Operations&quot;">​</a></h3><h4 id="utf-8-validation-utf8-valid-str-→-bool" tabindex="-1">UTF-8 Validation: <code>utf8_valid(str)</code> → <code>bool</code> <a class="header-anchor" href="#utf-8-validation-utf8-valid-str-→-bool" aria-label="Permalink to &quot;UTF-8 Validation: `utf8_valid(str)` → `bool`&quot;">​</a></h4><p>Checks if a string contains valid UTF-8.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let valid = utf8_valid(&quot;Hello, 世界!&quot;); // Returns true</span></span>\n<span class="line"><span>let invalid = utf8_valid(&amp;[0xFF, 0xFF]); // Returns false</span></span></code></pre></div><h4 id="utf-8-character-count-utf8-char-count-str-→-usize" tabindex="-1">UTF-8 Character Count: <code>utf8_char_count(str)</code> → <code>usize</code> <a class="header-anchor" href="#utf-8-character-count-utf8-char-count-str-→-usize" aria-label="Permalink to &quot;UTF-8 Character Count: `utf8_char_count(str)` → `usize`&quot;">​</a></h4><p>Returns the number of Unicode characters in a UTF-8 string.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let count = utf8_char_count(&quot;Hello, 世界!&quot;); // Returns 9 (not byte count)</span></span></code></pre></div><h4 id="utf-8-character-at-utf8-char-at-str-index-→-u32" tabindex="-1">UTF-8 Character At: <code>utf8_char_at(str, index)</code> → <code>u32</code> <a class="header-anchor" href="#utf-8-character-at-utf8-char-at-str-index-→-u32" aria-label="Permalink to &quot;UTF-8 Character At: `utf8_char_at(str, index)` → `u32`&quot;">​</a></h4><p>Returns the Unicode codepoint at the specified character index.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let codepoint = utf8_char_at(&quot;Hello, 世界!&quot;, 7); // Returns &#39;世&#39; (19990)</span></span></code></pre></div><h3 id="launch-expression-future" tabindex="-1">Launch Expression (Future) <a class="header-anchor" href="#launch-expression-future" aria-label="Permalink to &quot;Launch Expression (Future)&quot;">​</a></h3><p><strong>Syntax</strong>: <code>launch func[grid_dims](args)</code></p><p>Launches a function on parallel compute units (GPU, HPC clusters).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Launch kernel on GPU</span></span>\n<span class="line"><span>launch vector_add[1024, 1](a, b, result);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>// Multi-dimensional grid</span></span>\n<span class="line"><span>launch matrix_mul[32, 32](matrix_a, matrix_b, output);</span></span></code></pre></div><p><strong>Status</strong>: AST support exists, implementation pending.</p><p><strong>Note</strong>: This is a planned feature for high-performance computing integration.</p>',81)])])}const b=a(o,[["render",i]]);export{h as __pageData,b as default};
